CREATE INDEX IF NOT EXISTS idx_adv_snapshot_changes ON advertisement_snapshot USING GIN (changes_summary);
CREATE INDEX IF NOT EXISTS idx_photo_snapshot_changes ON photo_snapshot USING GIN (changes_summary);
CREATE INDEX IF NOT EXISTS idx_adv_snapshot_adv_version ON advertisement_snapshot (advertisement_id, version DESC);
CREATE INDEX IF NOT EXISTS idx_photo_snapshot_adv_version ON photo_snapshot (advertisement_id, version DESC);
